import Link from 'next/link';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Check } from 'lucide-react';
import { PLANS } from '@/lib/constants';

export function PricingCards() {
  return (
    <section className="py-24 bg-slate-50 dark:bg-slate-900/50" id="pricing">
      <div className="mx-auto max-w-7xl px-6">
        <div className="text-center mb-16">
          <h2 className="text-3xl font-bold tracking-tight sm:text-4xl">
            Simple, transparent pricing
          </h2>
          <p className="mt-4 text-lg text-muted-foreground">
            Start free and scale as you grow. No hidden fees.
          </p>
        </div>

        <div className="grid gap-8 lg:grid-cols-3 max-w-5xl mx-auto">
          {Object.entries(PLANS).map(([key, plan]) => (
            <Card
              key={key}
              className={`relative flex flex-col ${
                plan.popular
                  ? 'border-primary shadow-lg scale-105'
                  : ''
              }`}
            >
              {plan.popular && (
                <Badge className="absolute -top-3 left-1/2 -translate-x-1/2">
                  Most Popular
                </Badge>
              )}
              <CardHeader>
                <CardTitle className="text-xl">{plan.name}</CardTitle>
                <CardDescription>{plan.description}</CardDescription>
                <div className="mt-4">
                  <span className="text-4xl font-bold">${plan.price}</span>
                  {plan.price > 0 && (
                    <span className="text-muted-foreground">/month</span>
                  )}
                </div>
              </CardHeader>
              <CardContent className="flex-1">
                <ul className="space-y-3">
                  {plan.features.map((feature) => (
                    <li key={feature} className="flex items-start gap-3">
                      <Check className="h-4 w-4 text-primary mt-0.5 shrink-0" />
                      <span className="text-sm">{feature}</span>
                    </li>
                  ))}
                </ul>
              </CardContent>
              <CardFooter>
                <Button
                  asChild
                  className="w-full"
                  variant={plan.popular ? 'default' : 'outline'}
                >
                  <Link href="/signup">
                    {plan.price === 0 ? 'Get Started Free' : 'Start Free Trial'}
                  </Link>
                </Button>
              </CardFooter>
            </Card>
          ))}
        </div>
      </div>
    </section>
  );
}

import { Card, CardContent } from '@/components/ui/card';
import { Avatar, AvatarFallback } from '@/components/ui/avatar';

const testimonials = [
  {
    name: 'Sarah Chen',
    role: 'Operations Manager',
    company: 'TechFlow Inc.',
    content: 'NexusAI cut our invoice processing time by 80%. The AI extraction is incredibly accurate, even with messy scanned documents.',
    initials: 'SC',
  },
  {
    name: 'Marcus Johnson',
    role: 'Head of Product',
    company: 'GrowthLabs',
    content: 'The feedback analysis is a game-changer. We went from manually reading hundreds of responses to getting actionable insights in minutes.',
    initials: 'MJ',
  },
  {
    name: 'Emily Rodriguez',
    role: 'Customer Success Lead',
    company: 'ScaleUp Co.',
    content: 'Having document processing and survey analysis in one platform saves us from juggling multiple tools. The pricing is fair too.',
    initials: 'ER',
  },
];

export function Testimonials() {
  return (
    <section className="py-24 bg-background">
      <div className="mx-auto max-w-7xl px-6">
        <div className="text-center mb-16">
          <h2 className="text-3xl font-bold tracking-tight sm:text-4xl">
            Trusted by teams everywhere
          </h2>
          <p className="mt-4 text-lg text-muted-foreground">
            See what our customers have to say about NexusAI.
          </p>
        </div>

        <div className="grid gap-8 md:grid-cols-3">
          {testimonials.map((testimonial) => (
            <Card key={testimonial.name}>
              <CardContent className="pt-6">
                <p className="text-muted-foreground mb-6 leading-relaxed">
                  &ldquo;{testimonial.content}&rdquo;
                </p>
                <div className="flex items-center gap-3">
                  <Avatar>
                    <AvatarFallback className="bg-primary/10 text-primary text-sm">
                      {testimonial.initials}
                    </AvatarFallback>
                  </Avatar>
                  <div>
                    <p className="text-sm font-semibold">{testimonial.name}</p>
                    <p className="text-xs text-muted-foreground">
                      {testimonial.role} at {testimonial.company}
                    </p>
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      </div>
    </section>
  );
}

import { Metadata } from 'next';
import Link from 'next/link';
import { Button } from '@/components/ui/button';
import { PricingCards } from '@/components/landing/pricing-cards';
import { Footer } from '@/components/landing/footer';

export const metadata: Metadata = {
  title: 'Pricing',
  description: 'Simple, transparent pricing for NexusAI. Start free and scale as you grow.',
};

export default function PricingPage() {
  return (
    <div className="min-h-screen">
      <nav className="border-b bg-background">
        <div className="mx-auto max-w-7xl px-6">
          <div className="flex h-16 items-center justify-between">
            <Link href="/" className="flex items-center gap-2">
              <div className="flex h-8 w-8 items-center justify-center rounded-lg bg-primary">
                <span className="text-sm font-bold text-primary-foreground">N</span>
              </div>
              <span className="text-lg font-bold">NexusAI</span>
            </Link>
            <div className="flex items-center gap-3">
              <Button asChild variant="ghost">
                <Link href="/login">Sign In</Link>
              </Button>
              <Button asChild>
                <Link href="/signup">Get Started</Link>
              </Button>
            </div>
          </div>
        </div>
      </nav>
      <PricingCards />
      <Footer />
    </div>
  );
}
